class Solution {
    longestUniqueSubstring(s) {
        const freq = {};
        let left = 0;
        let longest = 0;

        for (let right = 0; right < s.length; right++) {
            const ch = s[right];
            freq[ch] = (freq[ch] || 0) + 1;

            while (freq[ch] > 1) {
                freq[s[left]]--;
                left++;
            }

            longest = Math.max(longest, right - left + 1);
        }

        return longest;
    }
